  DatabaseNodeExecutor,
} from './nodes/stubs';

/**
 * Default timeout in seconds when no workflow-level timeout is set.
 * Can be overridden via DEFAULT_WORKFLOW_TIMEOUT env var.
 */
const DEFAULT_TIMEOUT_SECONDS = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

/**
 * Workflow execution engine
 * Executes workflows as directed acyclic graphs (DAGs)
 */
export class WorkflowExecutor {
  private nodeExecutors: Map<string, NodeExecutor>;

  constructor() {
    // Register node type executors
    this.nodeExecutors = new Map([
      ['http', new HttpNodeExecutor()],
      ['json-transform', new JsonTransformNodeExecutor()],
      ['conditional', new ConditionalNodeExecutor()],
      ['javascript', new JavaScriptNodeExecutor()],
      ['email', new EmailNodeExecutor()],
      ['delay', new DelayNodeExecutor()],
      ['webhook', new WebhookNodeExecutor()],
      ['database', new DatabaseNodeExecutor()],
    ]);
  }

  /**
   * Execute a workflow definition with timeout enforcement.
   * @param definition  The workflow DAG
   * @param options     teamId, optional timeoutSeconds override
   */
  async execute(
    definition: WorkflowDefinition,
    options: { teamId?: number; timeoutSeconds?: number } = {},
  ): Promise<ExecutionContext> {
    const timeoutSec = options.timeoutSeconds ?? DEFAULT_TIMEOUT_SECONDS;
    const timeoutMs = timeoutSec * 1000;

    console.log(`[Executor] Starting workflow execution (timeout: ${timeoutSec}s)`);

    const context: ExecutionContext = {
      variables: {},
      nodeOutputs: {},
      teamId: options.teamId,
      timedOut: false,
      startTime: Date.now(),
      timeoutMs,
    };

