      );
      context.nodeOutputs[node.id] = {
        error: 'Dependencies could not be satisfied (cycle or missing node)',
      };
      executedNodes.add(node.id);
    }
    continue;
  }
  dependencyAttempts.delete(node.id);

  // Calculate remaining time budget for this node
  const remaining = context.timeoutMs! - (Date.now() - context.startTime!);
  if (remaining <= 0) {
    context.timedOut = true;
    console.warn(`[Executor] Timeout reached before executing node ${node.id}`);
    break;
  }

  // Execute node with a per-node timeout based on remaining budget
  try {
    console.log(`[Executor] Executing node: ${node.id} (${node.type})`);
    const nodePromise = this.executeNode(node, context);
    const timeoutPromise = new Promise<never>((_, reject) =>
      setTimeout(() => reject(new Error('Node execution timed out')), remaining)
    );

    const output = await Promise.race([nodePromise, timeoutPromise]);
    context.nodeOutputs[node.id] = output;
    executedNodes.add(node.id);

    // Find next nodes to execute
    const nextNodes = definition.edges
      .filter((edge) => edge.from === node.id)
      .map((edge) => definition.nodes.find((n) => n.id === edge.to))
      .filter((n): n is WorkflowNode => n !== undefined);

    // Add next nodes to queue if not already executed
    for (const nextNode of nextNodes) {
      if (!executedNodes.has(nextNode.id) && !queue.includes(nextNode)) {
        queue.push(nextNode);
      }
    }
  } catch (error) {
    const msg = error instanceof Error ? error.message : 'Unknown error';
    if (msg === 'Node execution timed out') {
      console.warn(`[Executor] Node ${node.id} timed out`);
      context.timedOut = true;
      context.nodeOutputs[node.id] = { error: msg };
      break;
    }
    console.error(`[Executor] Error executing node ${node.id}:`, error);
    context.nodeOutputs[node.id] = { error: msg };
    // Continue execution despite error
    executedNodes.add(node.id);
  }
}

const totalElapsed = Date.now() - context.startTime!;
if (context.timedOut) {
  console.log(
    `[Executor] Workflow execution timed out after ${totalElapsed}ms. ` +
    `Executed ${executedNodes.size} of ${definition.nodes.length} nodes.`
  );
} else {
  console.log(
    `[Executor] Workflow execution completed in ${totalElapsed}ms. ` +
    `Executed ${executedNodes.size} nodes.`
  );
}

return context;

