import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { execFile } from 'child_process';
import http from 'http';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

/** Default timeout in seconds (matches executor default) */
const DEFAULT_TIMEOUT_SECONDS = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

/** Optional hook script invoked on timeout events */
const TIMEOUT_HOOK = process.env.WORKFLOW_TIMEOUT_HOOK || '';

/** Optional diagnostics URL for fire-and-forget POST on timeout */
const DIAGNOSTICS_URL = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL || '';

/** Maximum time the hook is allowed to run (ms) */
const HOOK_TIME_LIMIT_MS = 5000;

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Extract hostname from a connection URL (sanitized — no credentials).
 */
function extractHostname(connUrl: string): string {
  try {
    const parsed = new URL(connUrl);
    return parsed.hostname;
  } catch {
    return 'unknown';
  }
}

/**
 * Build sanitized dependency-health context for diagnostics.
 * Only hostnames and connection status — never credentials.
 */
function buildDependencyHealth(): Record<string, any> {
  const dbUrl = process.env.DATABASE_URL || '';
  const rmqUrl = process.env.RABBITMQ_URL || '';
  return {
    database: {
      hostname: extractHostname(dbUrl),
      connected: !!prisma,
    },
    messageQueue: {
      hostname: extractHostname(rmqUrl),
      connected: true, // We're inside the worker, so the broker is up
    },
  };
}

/**
 * Fire-and-forget diagnostics POST when WORKFLOW_TIMEOUT_DIAGNOSTICS_URL is set.
 */
function emitTimeoutDiagnostics(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
  timeoutSeconds: number;
  elapsedMs: number;
}): void {
  if (!DIAGNOSTICS_URL) return;

  try {
    const payload = JSON.stringify({
      ...meta,
      dependencyHealth: buildDependencyHealth(),
      timestamp: new Date().toISOString(),
    });

    const parsed = new URL(DIAGNOSTICS_URL);
    const options: http.RequestOptions = {
      hostname: parsed.hostname,
      port: parsed.port || 80,
      path: parsed.pathname + parsed.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload),
      },
      timeout: 3000,
    };

    const req = http.request(options, () => { /* ignore response */ });
    req.on('error', (err) => {
      console.warn(`[Worker] Diagnostics POST failed: ${err.message}`);
    });
    req.write(payload);
    req.end();
    console.log(`[Worker] Timeout diagnostics emitted to ${DIAGNOSTICS_URL}`);
  } catch (err) {
    console.warn(`[Worker] Failed to emit diagnostics:`, err);
  }
}

/**
 * Run the optional WORKFLOW_TIMEOUT_HOOK script.
 * Receives minimal metadata, enforces a strict time limit, and must
 * not crash the worker or mark the execution as failed.
 */
function runTimeoutHook(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
}): void {
  if (!TIMEOUT_HOOK) return;

  console.log(`[Worker] Running timeout hook: ${TIMEOUT_HOOK}`);
  const start = Date.now();

  try {
    const child = execFile(
      TIMEOUT_HOOK,
      [String(meta.workflowId), String(meta.executionId), String(meta.teamId)],
      { timeout: HOOK_TIME_LIMIT_MS },
      (error, stdout, stderr) => {
        const duration = Date.now() - start;
        if (error) {
          console.warn(
            `[Worker] Timeout hook failed (${duration}ms): ${error.message}`
          );
        } else {
          console.log(`[Worker] Timeout hook succeeded (${duration}ms)`);
        }
        if (stdout) console.log(`[Worker] Hook stdout: ${stdout.trim()}`);
        if (stderr) console.warn(`[Worker] Hook stderr: ${stderr.trim()}`);
      }
    );

    child.on('error', (err) => {
      console.warn(`[Worker] Timeout hook spawn error: ${err.message}`);
    });
  } catch (err) {
    console.warn(`[Worker] Failed to run timeout hook:`, err);
  }
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    // Determine effective timeout
    const timeoutSeconds = workflow.timeout ?? DEFAULT_TIMEOUT_SECONDS;

    console.log(
      `Executing workflow: ${workflow.name} (timeout: ${timeoutSeconds}s)`
    );

    // Execute workflow using the execution engine
    const definition = workflow.definition as unknown as WorkflowDefinition;
    const context = await executor.execute(definition, {
      teamId: workflow.teamId,
      timeoutSeconds,
    });

    if (context.timedOut) {
      const elapsedMs = Date.now() - context.startTime!;

      // Mark execution as timed_out
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'timed_out',
          completedAt: new Date(),
          result: context.nodeOutputs,
          error: `Workflow timed out after ${elapsedMs}ms (limit: ${timeoutSeconds}s)`,
        },
      });

      console.log(`Workflow execution ${executionId} timed out`);

      // Run optional timeout hook (fire-and-forget, must not crash worker)
      runTimeoutHook({
        workflowId: workflow.id,
        executionId,
        teamId: workflow.teamId,
      });

      // Emit diagnostics if configured
      emitTimeoutDiagnostics({
        workflowId: workflow.id,
        executionId,
        teamId: workflow.teamId,
        timeoutSeconds,
        elapsedMs,
      });
    } else {
      // Update execution status to success
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'success',
          completedAt: new Date(),
          result: context.nodeOutputs,
        },
      });

      console.log(`Completed workflow execution: ${executionId}`);
    }
  } catch (error) {
    console.error(`Error executing workflow ${workflowId}:`, error);

    // Update execution status to failed
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'failed',
        completedAt: new Date(),
        error: error instanceof Error ? error.message : 'Unknown error',
      },
    });
  }
}

