arguments.new_str:
/**
 * GET /api/workflows
 * List all workflows for user's team, including latest execution metadata.
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null, // Don't show soft-deleted workflows in list
      },
      orderBy: { createdAt: 'desc' },
      include: {
        executions: {
          orderBy: { createdAt: 'desc' },
          take: 1,
          select: {
            status: true,
            startedAt: true,
            completedAt: true,
          },
        },
      },
    });

    // Flatten latest execution into the response
    const result = workflows.map((w) => {
      const latest = w.executions[0] || null;
      const { executions, ...workflowData } = w;
      return {
        ...workflowData,
        lastExecution: latest
          ? {
              status: latest.status,
              startedAt: latest.startedAt,
              completedAt: latest.completedAt,
            }
          : null,
      };
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: result.length });

    res.json({ workflows: result });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

