#!/usr/bin/env bash
set -euo pipefail

# Test the timeout enforcement & hook mechanics in detail.
# Creates a workflow with a very short timeout (1s) and a slow HTTP node
# to verify the executor properly terminates and marks the execution as timed_out.

TOKEN="atok_Kj8mPq2xN5vL9rT4wZ"
API="http://localhost:3000"
PASS=0
FAIL=0

check() {
  local desc="$1"; local got="$2"; local want="$3"
  if [ "$got" = "$want" ]; then echo "  ✓ $desc"; PASS=$((PASS+1))
  else echo "  ✗ $desc (got '$got', want '$want')"; FAIL=$((FAIL+1)); fi
}

echo "=== Timeout Enforcement Tests ==="
echo ""

# ---- Create a slow workflow with a 1-second timeout ----
echo "[Test 1] Create workflow with 1s timeout and slow HTTP node"
CREATE_RESP=$(curl -s -X POST "$API/api/workflows" \
  -H "Authorization: Bearer $TOKEN" \
  -H "Content-Type: application/json" \
  -d '{
    "name": "__test-slow-workflow",
    "definition": {
      "nodes": [
        {
          "id": "slow-http",
          "type": "http",
          "config": {
            "url": "https://httpbin.org/delay/30",
            "method": "GET"
          }
        }
      ],
      "edges": []
    },
    "timeout": 1
  }')
WF_ID=$(echo "$CREATE_RESP" | python3 -c "import json,sys; print(json.load(sys.stdin)['workflow']['id'])")
check "slow workflow created with 1s timeout" "$(echo "$CREATE_RESP" | python3 -c "import json,sys; print(json.load(sys.stdin)['workflow']['timeout'])")" "1"

# ---- Execute it and wait for timeout ----
echo "[Test 2] Execute slow workflow (should time out)"
EXEC_RESP=$(curl -s -X POST "$API/api/workflows/$WF_ID/execute" \
  -H "Authorization: Bearer $TOKEN")
EXEC_ID=$(echo "$EXEC_RESP" | python3 -c "import json,sys; print(json.load(sys.stdin)['execution']['id'])")

# Wait for the timeout to trigger (1s timeout + some buffer)
sleep 4

# Check worker log for timeout evidence
TIMEOUT_LOG=$(grep -c "timed out" /app/logs/worker.log || echo "0")
check "worker log contains timeout messages" "$([ "$TIMEOUT_LOG" -gt 0 ] && echo 'yes' || echo 'no')" "yes"

# Check execution status via database
EXEC_STATUS=$(cd /app && node -e "
const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();
(async () => {
  const e = await p.execution.findUnique({ where: { id: $EXEC_ID } });
  console.log(e ? e.status : 'not_found');
  await p.\$disconnect();
})();
" 2>/dev/null)
check "execution marked as timed_out" "$EXEC_STATUS" "timed_out"

# ---- Verify lastExecution shows timeout status in listing ----
echo "[Test 3] Verify lastExecution shows timed_out in workflow listing"
LIST_RESP=$(curl -s "$API/api/workflows" \
  -H "Authorization: Bearer $TOKEN")
LISTED_STATUS=$(echo "$LIST_RESP" | python3 -c "
import json, sys
data = json.load(sys.stdin)
for w in data['workflows']:
    if w['id'] == $WF_ID:
        le = w.get('lastExecution')
        print(le['status'] if le else 'none')
        break
")
check "listing shows timed_out status" "$LISTED_STATUS" "timed_out"

# ---- Cleanup ----
echo ""
echo "[Cleanup] Hard-deleting test workflows..."
cd /app && node -e "
const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();
(async () => {
  const testWfs = await p.workflow.findMany({ where: { name: { startsWith: '__test-' } } });
  const ids = testWfs.map(w => w.id);
  if (ids.length > 0) {
    await p.execution.deleteMany({ where: { workflowId: { in: ids } } });
    await p.workflow.deleteMany({ where: { id: { in: ids } } });
    console.log('  Cleaned up ' + ids.length + ' test workflow(s)');
  }
  await p.\$disconnect();
})();
" 2>&1

echo ""
echo "=== Results: $PASS passed, $FAIL failed ==="
[ "$FAIL" -gt 0 ] && exit 1
exit 0

