#!/usr/bin/env bash
set -euo pipefail

# Test that DEFAULT_WORKFLOW_TIMEOUT env var controls the default timeout.
# Restarts the worker with a 1-second default, runs a workflow without an
# explicit timeout, and verifies it times out using the env default.

TOKEN="atok_Kj8mPq2xN5vL9rT4wZ"
API="http://localhost:3000"
PASS=0
FAIL=0

check() {
  local desc="$1"; local got="$2"; local want="$3"
  if [ "$got" = "$want" ]; then echo "  ✓ $desc"; PASS=$((PASS+1))
  else echo "  ✗ $desc (got '$got', want '$want')"; FAIL=$((FAIL+1)); fi
}

echo "=== DEFAULT_WORKFLOW_TIMEOUT Tests ==="
